package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Locator;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertFalse;public class HP22ProductoDeshabilitadoNoVisiblePlaywrightTest extends BaseTestPlaywright {    @Test    void productoDeshabilitadoNoApareceEnDesplegable() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("camarero");        page.locator("input[name='password']")                .fill("123");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        page.locator("a:has-text('Crear pedido'), a:has-text('Crear Pedido')")                .first()                .click();        page.waitForLoadState();        Locator opciones = page.locator("select option");        StringBuilder textoOpciones = new StringBuilder();        int totalOpciones = (int) opciones.count();        for (int i = 0; i < totalOpciones; i++) {            textoOpciones.append(" ")                    .append(opciones.nth(i).textContent().toLowerCase());        }        assertFalse(                textoOpciones.toString().contains("causa rellena"),                "El producto deshabilitado 'Causa rellena' aparece en el desplegable de productos disponibles."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP22-producto-deshabilitado-no-visible.png"))                        .setFullPage(true)        );    }}